// Extract all product links from HTML content, parse URLs, group by maincat
// Based on link_validator.py: extract_hyperlinks_from_content(), extract_from_url(), lookup_plp_urls_for_content()

const content = $json.content || '';
const contentUrl = $json.url || '';
const createdAt = $json.created_at || '';

// Maincat URL -> maincat_id mapping (from maincat_mapping.csv)
const maincatMapping = {
  'meubilair': '10', 'speelgoed_spelletjes': '332', 'parfum_aftershave': '29000',
  'cddvdrom': '4', 'sieraden_horloges': '347', 'muziekinstrument': '31000',
  'schoenen': '32000', 'mode': '137', 'mode_accessoires': '33000',
  'dieren_accessoires': '34000', 'autos': '37000', 'sport_outdoor_vrije-tijd': '206',
  'fietsen': '38000', 'klussen': '35000', 'tuin_accessoires': '36000',
  'huis_tuin': '165', 'kantoorartikelen': '361', 'main_sanitair': '27000',
  'gezond_mooi': '286', 'voor_volwassenen': '452', 'baby_peuter': '8',
  'cadeaus_gadgets_culinair': '262', 'eten_drinken': '11', 'accessoires': '40000',
  'horloge': '30000', 'films-series': '700', 'boeken': '701',
  'software': '155', 'computers': '6', 'elektronica': '655',
  'huishoudelijke_apparatuur': '12000'
};

// 1. Extract all <a href="/p/..."> links using regex
const hrefRegex = /<a[^>]*href="([^"]*\/p\/[^"]*?)"[^>]*>/gi;
const links = [];
let match;
while ((match = hrefRegex.exec(content)) !== null) {
  let href = match[1];
  if (href.startsWith('https://www.beslist.nl')) {
    href = href.replace('https://www.beslist.nl', '');
  }
  links.push(href);
}
const uniqueLinks = [...new Set(links)];

// 2. Parse each link to get maincat_id and lookup value
function extractFromUrl(url) {
  const cleanUrl = url.replace(/\/$/, '');
  const parts = cleanUrl.split('/');

  // Try old format: /{maincat_url}/{pimId_with_prefix}/
  for (const [urlPart, maincatId] of Object.entries(maincatMapping)) {
    if (url.includes(`/${urlPart}/`)) {
      const pimId = parts[parts.length - 1] || null;
      return { maincatId, lookupValue: pimId, isV4: false };
    }
  }

  // Try new format: /p/name/{maincat_id}/{pimId}/
  if (parts.length >= 2) {
    const potentialMaincat = parts[parts.length - 2];
    const potentialPimId = parts[parts.length - 1];

    if (/^\d+$/.test(potentialMaincat)) {
      if (potentialPimId.startsWith('V4_')) {
        // V4 UUID format
        const pIdx = url.indexOf('/p/');
        if (pIdx !== -1) {
          const plpPath = url.substring(pIdx) + '/';
          return { maincatId: potentialMaincat, lookupValue: plpPath, isV4: true };
        }
        return { maincatId: null, lookupValue: null, isV4: false };
      } else if (/^\d+$/.test(potentialPimId)) {
        // New numeric format - add nl-nl-gold- prefix
        return { maincatId: potentialMaincat, lookupValue: `nl-nl-gold-${potentialPimId}`, isV4: false };
      }
    }
  }

  return { maincatId: null, lookupValue: null, isV4: false };
}

// 3. Group by maincat_id for batch ES queries
const pimIdGroups = {};  // { maincatId: { pimId: originalUrl } }
const v4Groups = {};     // { maincatId: { v4Uuid: originalUrl } }
const urlToLookup = {};  // { originalUrl: { lookupValue, isV4 } }

for (const link of uniqueLinks) {
  const { maincatId, lookupValue, isV4 } = extractFromUrl(link);
  if (maincatId && lookupValue) {
    urlToLookup[link] = { lookupValue, isV4 };
    if (isV4) {
      if (!v4Groups[maincatId]) v4Groups[maincatId] = {};
      v4Groups[maincatId][lookupValue] = link;
    } else {
      if (!pimIdGroups[maincatId]) pimIdGroups[maincatId] = {};
      pimIdGroups[maincatId][lookupValue] = link;
    }
  }
}

return {
  json: {
    contentUrl,
    content,
    createdAt,
    uniqueLinks,
    pimIdGroups,
    v4Groups,
    urlToLookup,
    totalLinks: uniqueLinks.length
  }
};

// Query Elasticsearch for each maincat group and collect results
// Based on link_validator.py: query_elasticsearch() and query_elasticsearch_by_plpurl()

const ES_URL = 'https://elasticsearch-job-cluster-eck.beslist.nl';
const INDEX_PREFIX = 'product_search_v4_nl-nl_';

const pimIdGroups = $json.pimIdGroups || {};
const v4Groups = $json.v4Groups || {};

// Results: lookupValue -> plpUrl (or null if gone)
const lookupResults = {};

// Query by pimId for regular URLs
for (const [maincatId, pimIdMap] of Object.entries(pimIdGroups)) {
  const index = `${INDEX_PREFIX}${maincatId}`;
  const pimIds = Object.keys(pimIdMap);

  if (pimIds.length === 0) continue;

  try {
    const response = await fetch(`${ES_URL}/${index}/_search`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        _source: ['plpUrl', 'pimId', 'shopCount'],
        size: pimIds.length,
        query: { terms: { pimId: pimIds } }
      })
    });

    const data = await response.json();
    const hits = (data.hits && data.hits.hits) || [];

    const found = new Set();
    for (const hit of hits) {
      const src = hit._source || {};
      const pimId = src.pimId;
      const plpUrl = src.plpUrl;
      const shopCount = src.shopCount || 0;

      if (pimId) {
        found.add(pimId);
        lookupResults[pimId] = (shopCount >= 2 && plpUrl) ? plpUrl : null;
      }
    }

    // Mark unfound pimIds as gone
    for (const pimId of pimIds) {
      if (!found.has(pimId)) {
        lookupResults[pimId] = null;
      }
    }
  } catch (e) {
    // ES query failed - skip this batch, don't mark as gone
    console.log(`ES error for ${index}: ${e.message}`);
  }
}

// Query by pimId for V4 URLs (fast path only, wildcard disabled)
for (const [maincatId, v4Map] of Object.entries(v4Groups)) {
  const index = `${INDEX_PREFIX}${maincatId}`;
  const plpUrls = Object.keys(v4Map);

  // Extract V4 UUIDs for pimId lookup
  const v4Uuids = [];
  const v4ToOriginal = {};
  for (const plpUrl of plpUrls) {
    const parts = plpUrl.replace(/\/$/, '').split('/');
    const v4Part = parts[parts.length - 1];
    if (v4Part && v4Part.startsWith('V4_')) {
      v4Uuids.push(v4Part);
      v4ToOriginal[v4Part] = plpUrl;
    }
  }

  if (v4Uuids.length === 0) continue;

  try {
    const response = await fetch(`${ES_URL}/${index}/_search`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        _source: ['plpUrl', 'pimId', 'shopCount'],
        size: v4Uuids.length,
        query: { terms: { pimId: v4Uuids } }
      })
    });

    const data = await response.json();
    const hits = (data.hits && data.hits.hits) || [];

    for (const hit of hits) {
      const src = hit._source || {};
      const pimId = src.pimId || '';
      const plpUrl = src.plpUrl;
      const shopCount = src.shopCount || 0;

      if (pimId in v4ToOriginal) {
        const originalPath = v4ToOriginal[pimId];
        lookupResults[originalPath] = (shopCount >= 2 && plpUrl) ? plpUrl : null;
      }
    }
    // V4 URLs not found are skipped (not marked as gone) - wildcard disabled
  } catch (e) {
    console.log(`V4 ES error for ${index}: ${e.message}`);
  }
}

return {
  json: {
    ...$json,
    lookupResults
  }
};

// Compare ES results with original URLs, categorize and build corrected content
// Based on link_validator.py: validate_and_fix_content_links()

const content = $json.content;
const contentUrl = $json.contentUrl;
const createdAt = $json.createdAt || '';
const urlToLookup = $json.urlToLookup || {};
const lookupResults = $json.lookupResults || {};
const uniqueLinks = $json.uniqueLinks || [];
const totalLinks = $json.totalLinks || 0;

const validUrls = [];
const replacedUrls = [];
const goneUrls = [];

let correctedContent = content;

for (const link of uniqueLinks) {
  const info = urlToLookup[link];
  if (!info) {
    // Could not parse URL - treat as gone
    goneUrls.push(link);
    continue;
  }

  const { lookupValue } = info;

  if (!(lookupValue in lookupResults)) {
    // ES query failed or not found - skip, don't mark as gone
    validUrls.push(link);
    continue;
  }

  const correctPlpUrl = lookupResults[lookupValue];

  if (correctPlpUrl === null) {
    // Product is GONE (not found or shopCount < 2)
    goneUrls.push(link);
  } else if (correctPlpUrl !== link) {
    // URL needs replacement
    correctedContent = correctedContent.split(link).join(correctPlpUrl);
    replacedUrls.push({ old_url: link, new_url: correctPlpUrl });
  } else {
    validUrls.push(link);
  }
}

// Sanitize corrected content for SQL
const sanitizedCorrected = correctedContent.replace(/'/g, "''");

const hasGone = goneUrls.length > 0;
const hasReplacements = replacedUrls.length > 0;
const hasChanges = hasReplacements && !hasGone;

// Build broken_link_details JSON for validation results table
const brokenLinkDetails = JSON.stringify({
  gone_urls: goneUrls,
  replaced_urls: replacedUrls
}).replace(/'/g, "''");

return {
  json: {
    contentUrl,
    content,
    createdAt,
    correctedContent: sanitizedCorrected,
    validUrls,
    replacedUrls,
    goneUrls,
    hasGone,
    hasReplacements,
    hasChanges,
    totalLinks,
    validCount: validUrls.length + replacedUrls.length,
    goneCount: goneUrls.length,
    brokenLinkDetails
  }
};
